#include<bits/stdc++.h>
using namespace std;
int a[25],sum=0,luji[25],size=0,n,ans_luji[25];
bool f[25][25],vis[25];
bool DI(int wi){
	for(int i=1;i<=n;i++)
		if(f[wi][i]&&!vis[i])return false;
 	return true;
}
void dfs(int wi,int len,int su){
	if(DI(wi)){
		if(su>sum){
			sum=su,size=len;
			for(int i=1;i<=len;i++)ans_luji[i]=luji[i];
		}return;
	} 
	for(int i=1;i<=n;i++){
		if(f[wi][i]&&!vis[i]){
			vis[i]=true,luji[len+1]=i;
			dfs(i,len+1,su+a[i]);
			vis[i]=false;
		}
		
	}
}
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	for(int i=1;i<n;i++)for(int j=i+1;j<=n;j++)cin>>f[i][j];
	for(int i=1;i<=n;i++){
		vis[i]=1,luji[1]=i;
		dfs(i,1,a[i]);vis[i]=0;
	}
	for(int i=1;i<=size;i++)cout<<ans_luji[i]<<' ';
	cout<<"\n"<<sum;
	return false;
}
